// ═══════════════════════════════════════════════════════
// Step 12: Report-Tabelle erstellen
// Erzeugt eine strukturierte Tabelle mit allen Ergebnissen.
// Unterstuetzt mehrere Mitbewerber: pro Mitbewerber eine Spalte.
// ═══════════════════════════════════════════════════════
const data = $input.item.json;
const config = data.config;
const einzelvergleiche = data.einzelvergleiche || [];
const competitors = data.competitors || [];

// Pivot: Fakten als Zeilen, Mitbewerber als Spalten
const byFact = new Map();
for (const e of einzelvergleiche) {
  if (!byFact.has(e.id)) {
    byFact.set(e.id, {
      Nr: e.id,
      Kategorie: e.kategorie,
      Aspekt: e.aspekt,
      [config.ownCompanyShort]: e.own_data
    });
  }
  const row = byFact.get(e.id);
  row[e.competitorShort] = e.kurzfassung || (e.vergleich_aus_rag || '').substring(0, 120) + ((e.vergleich_aus_rag || '').length > 120 ? '...' : '');
  row[e.competitorShort + '_Bewertung'] = e.bewertung || 'nicht ermittelt';
  row[e.competitorShort + '_RAG_Chunks'] = e.ragChunkCount;
  row[e.competitorShort + '_Tokens'] = e.tokens;
}

const reportTable = [...byFact.values()];

// Zusammenfassung pro Mitbewerber
const summaries = competitors.map(comp => {
  const compResults = einzelvergleiche.filter(e => e.competitorShort === comp.short);
  const ownBetter = compResults.filter(e => (e.bewertung || '').toLowerCase().includes(config.ownCompanyShort.toLowerCase() + ' besser')).length;
  const compBetter = compResults.filter(e => (e.bewertung || '').toLowerCase().includes(comp.short.toLowerCase() + ' besser')).length;
  const equal = compResults.filter(e => (e.bewertung || '').toLowerCase().includes('gleichwertig')).length;
  return {
    competitor: comp.name,
    competitorShort: comp.short,
    totalFacts: compResults.length,
    ownBetter,
    competitorBetter: compBetter,
    equal,
    unclear: compResults.length - ownBetter - compBetter - equal
  };
});

return {
  reportTable,
  summaries,
  competitors,
  gesamtvergleich: data.gesamtvergleich,
  config,
  meta: {
    model: data.model,
    usage: data.usage,
    timestamp: data.timestamp,
    status: data.status
  }
};
